// assets.js — bundled image assets for effects ported from tooooools.app
// (the 6 halftone "patterns" tiles + the displacement map used by `distort`).
// Classic script, attaches to window.RSTR like every other src/*.js file.
//
// Assets are embedded as base64 data URIs (not relative file paths) so this
// works over file:// without canvas-tainting the source image (Chrome taints
// canvases drawn from cross-origin/file:// <img> sources unless the image
// itself came in as a data: URI).
//
// On load, each PNG is decoded via an off-DOM <img> + canvas.getImageData()
// into a plain ImageData:
//   RSTR.assets.patterns      -> array of 6 ImageData, 100x100 each
//   RSTR.assets.displacement  -> ImageData, 600x600
// RSTR.assetsReady is a Promise that resolves once both are decoded. CPU
// stages that depend on these assets must check RSTR.assets is populated
// before use and return the input unchanged otherwise (assets decode
// asynchronously, so the very first render after page load can race it).
(function (RSTR) {
  'use strict';

  const PATTERN_DATA_URIS = [
    'data:image/png;base64,', // pattern-1.png (100x100)
    'data:image/png;base64,', // pattern-2.png (100x100)
    'data:image/png;base64,', // pattern-3.png (100x100)
    'data:image/png;base64,', // pattern-4.png (100x100)
    'data:image/png;base64,', // pattern-5.png (100x100)
    'data:image/png;base64,', // pattern-6.png (100x100)
  ];

  const DISPLACEMENT_DATA_URI = 'data:image/png;base64,'; // displacement.png (600x600)

  // Decode one data-URI PNG into an ImageData via an off-DOM canvas.
  function loadImageData(src) {
    return new Promise(function (resolve, reject) {
      const img = new Image();
      img.onload = function () {
        const canvas = document.createElement('canvas');
        canvas.width = img.naturalWidth;
        canvas.height = img.naturalHeight;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0);
        try {
          resolve(ctx.getImageData(0, 0, canvas.width, canvas.height));
        } catch (err) {
          reject(err);
        }
      };
      img.onerror = function () {
        reject(new Error('RSTR.assets: failed to decode image'));
      };
      img.src = src;
    });
  }

  RSTR.assets = RSTR.assets || {};

  RSTR.assetsReady = Promise.all([
    Promise.all(PATTERN_DATA_URIS.map(loadImageData)),
    loadImageData(DISPLACEMENT_DATA_URI),
  ]).then(function (results) {
    RSTR.assets.patterns = results[0];
    RSTR.assets.displacement = results[1];
  }).catch(function (err) {
    console.error('RSTR.assets: failed to load bundled assets', err);
  });
})((window.RSTR = window.RSTR || {}));
